MonsterGroupConfig = {}

MonsterGroupConfig.MonsterGroupData = {} --怪物组配置

function MonsterGroupConfig:init(config)
    --HostApi.log("MonsterGroupConfig:init")

    for _, configData in pairs(config) do
        local data = {}
        data.id = tonumber(configData.id) or 0
        data.MonsterGroupId = tonumber(configData.MonsterGroupId) or 0
        data.MonsterId = tonumber(configData.MonsterId) or 0
        data.Weights = tonumber(configData.Weights) or 0
        if self.MonsterGroupData[data.MonsterGroupId] == nil then
            self.MonsterGroupData[data.MonsterGroupId] = {}
        end
        table.insert(self.MonsterGroupData[data.MonsterGroupId], data)
    end
end

function MonsterGroupConfig:getMonsterGroupConfig(id)
    --
end

function MonsterGroupConfig:getAllMonsterFromGroup(monsterGroup)
    return self.MonsterGroupData[monsterGroup]
end

function MonsterGroupConfig:getMonsterFromGroup(monsterGroup)
    if self.MonsterGroupData[monsterGroup] == nil then
        --HostApi.log(string.format("MonsterGroupConfig:getMonsterFromGroup %d", monsterGroup))
        return -1
    end

    local sum = 0
    for _, data in pairs(self.MonsterGroupData[monsterGroup]) do
        sum = BaseUtil:incNumber(sum, data.Weights)
    end

    if sum <= 0 then
        return -1
    end

    local rate = math.random(sum)
    --HostApi.log("MonsterGroupConfig:getMonsterFromGroup " .. rate)

    sum = 0
    for _, data in pairs(self.MonsterGroupData[monsterGroup]) do
        sum = BaseUtil:incNumber(sum, data.Weights)
        if sum >= rate then
            --HostApi.log(string.format("MonsterGroupConfig:getMonsterFromGroup monsterGroup:%d MonsterId:%d",
            --        monsterGroup, data.MonsterId))
            return data.MonsterId;
        end
    end

    return -1
end

return MonsterGroupConfig